    12	
    13	// https://source.chromium.org/chromium/chromium/src/+/main:components/os_crypt/os_crypt_linux.cc
    14	var linuxParams = pbkdf2Params{
    15		salt:       []byte("saltysalt"),
    16		iterations: 1,
    17		keySize:    16,
    18		hashFunc:   sha1.New,
    19	}
    20	
    21	// DBusRetriever queries GNOME Keyring / KDE Wallet via D-Bus Secret Service.
    22	type DBusRetriever struct{}
    23	
    24	func (r *DBusRetriever) RetrieveKey(storage, _ string) ([]byte, error) {
    25		conn, err := dbus.SessionBus()
    26		if err != nil {
    27			return nil, fmt.Errorf("dbus session: %w", err)
    28		}
    29	
    30		svc, err := keyring.GetSecretService(conn)
    31		if err != nil {
    32			return nil, fmt.Errorf("secret service: %w", err)
    33		}
    34	
    35		session, err := svc.OpenSession()
    36		if err != nil {
    37			return nil, fmt.Errorf("open session: %w", err)
    38		}
    39		defer session.Close()
    40	
    41		collections, err := svc.GetAllCollections()
    42		if err != nil {
    43			return nil, fmt.Errorf("get collections: %w", err)
    44		}
    45	
    46		for _, col := range collections {
    47			items, err := col.GetAllItems()
    48			if err != nil {
    49				continue
    50			}
    51			for _, item := range items {
    52				label, err := item.GetLabel()
    53				if err != nil {
    54					continue
    55				}
    56				if label == storage {
    57					secret, err := item.GetSecret(session.Path())
    58					if err != nil {
    59						return nil, fmt.Errorf("get secret for %s: %w", storage, err)
    60					}
    61					if len(secret.Value) > 0 {
    62						return linuxParams.deriveKey(secret.Value), nil
    63					}
    64				}
    65			}
    66		}
    67	
    68		return nil, fmt.Errorf("%q: %w", storage, errStorageNotFound)
    69	}
    70	
    71	// FallbackRetriever uses the hardcoded "peanuts" password when D-Bus is unavailable.
    72	// https://source.chromium.org/chromium/chromium/src/+/main:components/os_crypt/os_crypt_linux.cc;l=100
    73	type FallbackRetriever struct{}
    74	
    75	func (r *FallbackRetriever) RetrieveKey(_, _ string) ([]byte, error) {
    76		return linuxParams.deriveKey([]byte("peanuts")), nil
    77	}
    78	
    79	// DefaultRetriever returns the Linux retriever chain:
    80	// D-Bus Secret Service first, then "peanuts" fallback.
    81	func DefaultRetriever() KeyRetriever {
    82		return NewChain(
    83			&DBusRetriever{},
    84			&FallbackRetriever{},
    85		)
    86	}
