   291	// hasAnySource checks if dir contains at least one source file or directory.
   292	func hasAnySource(sources map[types.Category][]sourcePath, dir string) bool {
   293		for _, candidates := range sources {
   294			for _, sp := range candidates {
   295				abs := filepath.Join(dir, sp.rel)
   296				if _, err := os.Stat(abs); err == nil {
   297					return true
   298				}
   299			}
   300		}
   301		return false
   302	}
   303	
   304	// resolvedPath holds the absolute path and type for a discovered source.
   305	type resolvedPath struct {
   306		absPath string
   307		isDir   bool
   308	}
   309	
   310	// resolveSourcePaths checks which sources actually exist in profileDir.
   311	// Candidates are tried in priority order; the first existing path wins.
   312	func resolveSourcePaths(sources map[types.Category][]sourcePath, profileDir string) map[types.Category]resolvedPath {
   313		resolved := make(map[types.Category]resolvedPath)
   314		for cat, candidates := range sources {
   315			for _, sp := range candidates {
   316				abs := filepath.Join(profileDir, sp.rel)
   317				info, err := os.Stat(abs)
   318				if err != nil {
   319					continue
   320				}
   321				if sp.isDir == info.IsDir() {
   322					resolved[cat] = resolvedPath{abs, sp.isDir}
   323					break
   324				}
   325			}
   326		}
   327		return resolved
   328	}
   329	
   330	// isSkippedDir returns true for directory names that should never be
   331	// treated as browser profiles.
   332	func isSkippedDir(name string) bool {
   333		switch name {
   334		case "System Profile", "Guest Profile", "Snapshot":
   335			return true
   336		}
   337		return false
   338	}
   339	
   340	// timeEpoch converts a WebKit/Chromium epoch timestamp (microseconds since
   341	// 1601-01-01) to a time.Time.
   342	func timeEpoch(epoch int64) time.Time {
   343		maxTime := int64(99633311740000000)
   344		if epoch > maxTime {
   345			return time.Date(2049, 1, 1, 1, 1, 1, 1, time.Local)
   346		}
   347		t := time.Date(1601, 1, 1, 0, 0, 0, 0, time.Local)
   348		d := time.Duration(epoch)
   349		for i := 0; i < 1000; i++ {
   350			t = t.Add(d)
   351		}
   352		return t
   353	}
